function generateGastricBypassQuestion() { return { baseId: "gastricBypass", categoryKey: "adult", part: loc("비만 수술","Bariatric"), emoji: "🍽️", title: loc("위 우회술 후 식이","Post-Gastric Bypass Diet"), desc: loc(`위 우회술 후 환자의 가장 흔한 합병증인 \"덤핑 증후군\" 예방 식이는?`,`Diet to prevent dumping syndrome after gastric bypass?`), choices: shuffle([{ text: loc("소량씩 자주, 단순당 회피, 식사 중 액체 섭취 X","Small frequent meals, avoid simple sugars, no fluids with meals"), effect: { hp: -2, rep: 22 }, log: loc("정답. 빠른 위 통과를 늦춤.","Correct. Slows rapid gastric emptying.") }, { text: loc("고당분 음료 권장","Encourage sugary drinks"), effect: { hp: -32, rep: -22 }, log: loc("덤핑 유발.","Triggers dumping.") }, { text: loc("식사 중 다량 물","Lots of water during meals"), effect: { hp: -28, rep: -20 }, log: loc("덤핑 유발.","Triggers dumping.") }, { text: loc("하루 1번 큰 식사","One large meal daily"), effect: { hp: -28, rep: -20 }, log: loc("부적절.","Inappropriate.") }]) }; }
function generateLiverBiopsyQuestion() { return { baseId: "liverBiopsy", categoryKey: "adult", part: loc("처치","Procedure"), emoji: "💉", title: loc("간 생검 후 자세","Post Liver Biopsy"), desc: loc(`간 생검 직후 환자의 자세는?`,`Position after liver biopsy?`), choices: shuffle([{ text: loc("우측 측와위 (생검 부위가 아래로) 2시간 이상","Right lateral position (biopsy site down) ≥2 hours"), effect: { hp: -2, rep: 22 }, log: loc("정답. 출혈 부위 압박으로 출혈 예방.","Correct. Compresses biopsy site to prevent bleeding.") }, { text: loc("좌측 측와위","Left lateral"), effect: { hp: -28, rep: -20 }, log: loc("출혈 위험.","Bleeding risk.") }, { text: loc("앙와위로 다리 거상","Supine with legs elevated"), effect: { hp: -25, rep: -15 }, log: loc("우측 측와가 표준.","RIGHT lateral is standard.") }, { text: loc("바로 일어나도 됨","Ambulate immediately"), effect: { hp: -32, rep: -22 }, log: loc("출혈·기흉 위험.","Bleeding/pneumothorax risk.") }]) }; }
