function generatePostpartumChillsQuestion() { return { baseId: "ppChills", categoryKey: "maternal", part: loc("산후","Postpartum"), emoji: "🤱", title: loc("산후 오한","Postpartum Chills"), desc: loc(`정상 분만 직후 산모가 약 30분간 오한·떨림을 호소한다. 적절한 간호는?`,`Mother shivering/chills for ~30 min after normal delivery. Appropriate action?`), choices: shuffle([{ text: loc("따뜻한 담요 제공·안심시키기 (정상 자율신경 반응)","Warm blankets and reassurance — normal autonomic response"), effect: { hp: -2, rep: 22 }, log: loc("정답. 출산 후 흔한 정상 반응.","Correct. Common normal post-birth response.") }, { text: loc("패혈증 의심으로 항생제","Suspect sepsis, give antibiotics"), effect: { hp: -28, rep: -20 }, log: loc("발열·악취 등 다른 징후 없으면 정상.","Normal if no fever/foul lochia.") }, { text: loc("긴급 검사","Emergency labs"), effect: { hp: -22, rep: -12 }, log: loc("간단한 보온이 우선.","Just warm her first.") }, { text: loc("아무 처치 안 함","No action"), effect: { hp: -15, rep: -8 }, log: loc("간호 부족.","Inadequate care.") }]) }; }
