function generateSpinaBifidaQuestion() { return { baseId: "spinaBifida", categoryKey: "pediatric", part: loc("선천기형","Congenital"), emoji: "👶", title: loc("이분척추증","Spina Bifida"), desc: loc(`이분척추증 신생아의 출생 직후 가장 우선되는 간호는?`,`Most important immediate nursing care for newborn with spina bifida?`), choices: shuffle([{ text: loc("복위 유지·낭 멸균 거즈로 보호·라텍스 회피","Prone position, sterile saline gauze on sac, latex precautions"), effect: { hp: -3, rep: 22 }, log: loc("정답. 낭 파열·감염 예방, 라텍스 알레르기 위험.","Correct. Prevent rupture/infection; latex allergy risk.") }, { text: loc("앙와위로 보온","Supine with warming"), effect: { hp: -38, rep: -28 }, log: loc("낭에 압력 - 파열 위험.","Pressure on sac risks rupture.") }, { text: loc("즉시 모유수유","Immediate breastfeeding"), effect: { hp: -25, rep: -15 }, log: loc("외과 응급 우선.","Surgical emergency first.") }, { text: loc("관찰만","Just observe"), effect: { hp: -38, rep: -28 }, log: loc("응급 처치 필요.","Active care needed.") }]) }; }
function generatePediatricIVFluidQuestion() { return { baseId: "pedIVFluid", categoryKey: "pediatric", part: loc("소아 수액","Pediatric Fluid"), emoji: "💧", title: loc("소아 유지 수액","Pediatric Maintenance Fluid"), desc: loc(`체중 20kg 아동의 24시간 유지 수액량(Holliday-Segar)은?`,`24-hour maintenance fluid for a 20kg child (Holliday-Segar)?`), choices: shuffle([{ text: loc("1500 mL/일","1500 mL/day"), effect: { hp: -2, rep: 22 }, log: loc("정답. 첫 10kg=100mL/kg, 다음 10kg=50mL/kg → 1000+500=1500.","Correct. 100/50/20 mL/kg rule: 1000+500=1500.") }, { text: loc("2000 mL/일","2000 mL/day"), effect: { hp: -25, rep: -15 }, log: loc("계산 오류.","Calculation off.") }, { text: loc("1000 mL/일","1000 mL/day"), effect: { hp: -22, rep: -12 }, log: loc("부족.","Too low.") }, { text: loc("3000 mL/일","3000 mL/day"), effect: { hp: -28, rep: -20 }, log: loc("과도.","Too high.") }]) }; }
