function generateSuicideContractQuestion() { return { baseId: "suicideContract", categoryKey: "psych", part: loc("자살 위험","Suicide Risk"), emoji: "🆘", title: loc("자살 \"안전 계약\"","Safety Contract"), desc: loc(`자살 위험 환자와의 \"자해 안 하겠다\" 안전 계약(no-harm contract)에 대한 옳은 설명은?`,`Correct statement about \"no-harm contract\" with suicidal patient?`), choices: shuffle([{ text: loc("효과 입증 안 됨 - 안전계획·24시간 관찰이 더 권장","Not evidence-based — safety planning and observation are preferred"), effect: { hp: -2, rep: 22 }, log: loc("정답. 현대 가이드라인은 \"safety planning\" 권장.","Correct. Modern guidelines recommend safety planning instead.") }, { text: loc("계약하면 100% 안전","100% safe if signed"), effect: { hp: -42, rep: -32 }, log: loc("위험한 오해.","Dangerous misconception.") }, { text: loc("계약만으로 퇴원 가능","Can discharge with contract"), effect: { hp: -45, rep: -32 }, log: loc("부적절.","Inappropriate.") }, { text: loc("법적 효력","Legally binding"), effect: { hp: -32, rep: -22 }, log: loc("법적 효력 없음.","No legal force.") }]) }; }
function generateSchizoPositiveSymptomQuestion() { return { baseId: "schizoPositive", categoryKey: "psych", part: loc("조현병","Schizophrenia"), emoji: "🧠", title: loc("조현병 양성 증상","Positive Symptoms"), desc: loc(`조현병의 양성 증상에 해당하는 것은?`,`Which is a POSITIVE symptom of schizophrenia?`), choices: shuffle([{ text: loc("환각·망상·와해된 언어","Hallucinations, delusions, disorganized speech"), effect: { hp: -2, rep: 22 }, log: loc("정답. 양성=정상에 더해지는 증상.","Correct. Positive = added behaviors.") }, { text: loc("감정 둔마","Flat affect"), effect: { hp: -22, rep: -12 }, log: loc("음성 증상.","Negative symptom.") }, { text: loc("무논리증","Alogia"), effect: { hp: -22, rep: -12 }, log: loc("음성 증상.","Negative.") }, { text: loc("무쾌감증","Anhedonia"), effect: { hp: -22, rep: -12 }, log: loc("음성 증상.","Negative.") }]) }; }
function generateAnxietyMedQuestion() { return { baseId: "anxietyMed", categoryKey: "psych", part: loc("불안 약물","Anxiety Drugs"), emoji: "💊", title: loc("범불안장애 1차약","GAD First-Line"), desc: loc(`범불안장애(GAD)의 장기 1차 약물은?`,`First-line long-term medication for generalized anxiety disorder?`), choices: shuffle([{ text: loc("SSRI/SNRI (Escitalopram, Venlafaxine 등)","SSRI/SNRI (e.g., escitalopram, venlafaxine)"), effect: { hp: -2, rep: 22 }, log: loc("정답. 벤조는 단기·필요시만.","Correct. Benzos are short-term/PRN only.") }, { text: loc("벤조다이아제핀 장기","Long-term benzodiazepines"), effect: { hp: -28, rep: -20 }, log: loc("의존성 위험.","Dependency risk.") }, { text: loc("아편제","Opioids"), effect: { hp: -38, rep: -28 }, log: loc("부적절.","Inappropriate.") }, { text: loc("스테로이드","Steroids"), effect: { hp: -32, rep: -22 }, log: loc("관련 없음.","Unrelated.") }]) }; }
function generatePulmonaryRehabQuestion() { return { baseId: "pulmonaryRehab", categoryKey: "adult", part: loc("호흡 재활","Pulmonary Rehab"), emoji: "🏃", title: loc("폐 재활 핵심","Pulmonary Rehab"), desc: loc(`COPD 환자의 폐 재활에서 가장 중요한 요소는?`,`Most important component of COPD pulmonary rehab?`), choices: shuffle([{ text: loc("운동 훈련 + 호흡법(pursed-lip)·체위 교육","Exercise training + breathing techniques (pursed-lip) + positioning education"), effect: { hp: -2, rep: 22 }, log: loc("정답. 운동 내성과 삶의 질 향상.","Correct. Improves exercise tolerance and QOL.") }, { text: loc("절대 안정","Strict bed rest"), effect: { hp: -32, rep: -22 }, log: loc("탈조건화 가속.","Accelerates deconditioning.") }, { text: loc("산소만 24시간","Just 24-hour O2"), effect: { hp: -22, rep: -12 }, log: loc("일부 권장이나 운동이 핵심.","Indicated in some but exercise is core.") }, { text: loc("강한 운동 매일","Daily vigorous exercise"), effect: { hp: -25, rep: -15 }, log: loc("점진적·감독 운동.","Gradual, supervised.") }]) }; }
function generateRosenbachQuestion() { return { baseId: "alcoholInsomnia", categoryKey: "psych", part: loc("알코올","Alcohol"), emoji: "🍷", title: loc("알코올 금단 불면","Alcohol Withdrawal Insomnia"), desc: loc(`알코올 의존 환자의 일주일 금주 후 불면 호소. 가장 안전한 처치는?`,`Alcohol-dependent patient with insomnia 1 week after stopping. Safest action?`), choices: shuffle([{ text: loc("비약물 (수면 위생, 인지행동) + 짧은 트라조돈 신중 사용","Non-pharm first (sleep hygiene, CBT) + cautious short-term trazodone"), effect: { hp: -2, rep: 22 }, log: loc("정답. 벤조·아편 회피.","Correct. Avoid benzos/opioids.") }, { text: loc("벤조다이아제핀 처방","Prescribe benzo"), effect: { hp: -32, rep: -22 }, log: loc("교차 의존 위험.","Cross-dependency risk.") }, { text: loc("저용량 알코올","Small amount of alcohol"), effect: { hp: -45, rep: -32 }, log: loc("재발 촉진.","Promotes relapse.") }, { text: loc("관찰만","Just observe"), effect: { hp: -22, rep: -12 }, log: loc("환자 고통 큼.","Significant distress.") }]) }; }

