function generateDownSyndromeQuestion() { return { baseId: "downSyndrome", categoryKey: "pediatric", part: loc("염색체 이상","Chromosomal"), emoji: "👶", title: loc("다운 증후군 핵심 위험","Down Syndrome Risks"), desc: loc(`다운 증후군 신생아에서 가장 흔히 동반되는 선천성 합병증은?`,`Most common congenital comorbidity in Down syndrome newborn?`), choices: shuffle([{ text: loc("선천성 심장질환 (AV septal defect 등)","Congenital heart defect (AV septal defect)"), effect: { hp: -2, rep: 22 }, log: loc("정답. 약 50% 동반·심장초음파 권장.","Correct. ~50% have CHD; echo recommended.") }, { text: loc("선천성 청각 정상","Normal hearing"), effect: { hp: -25, rep: -15 }, log: loc("청각 결함이 흔함.","Hearing defects common.") }, { text: loc("뇌성 마비","Cerebral palsy"), effect: { hp: -22, rep: -12 }, log: loc("관련 적음.","Less common.") }, { text: loc("간 기형","Liver malformation"), effect: { hp: -25, rep: -15 }, log: loc("주된 합병증 아님.","Not main comorbidity.") }]) }; }
function generateCleftLipQuestion() { return { baseId: "cleftLip", categoryKey: "pediatric", part: loc("선천기형","Congenital"), emoji: "👶", title: loc("구순구개열 수유","Cleft Lip Feeding"), desc: loc(`구순구개열 신생아 수유 시 가장 적절한 자세·기구는?`,`Best feeding position/equipment for cleft lip/palate newborn?`), choices: shuffle([{ text: loc("바로 세워 안고 특수 젖꼭지(Haberman 등) 사용","Upright position, special bottle (Haberman, etc.)"), effect: { hp: -2, rep: 22 }, log: loc("정답. 흡인 예방·압박 흡입 가능.","Correct. Prevents aspiration, enables compression feeding.") }, { text: loc("일반 젖병 누운 자세","Regular bottle, supine"), effect: { hp: -32, rep: -22 }, log: loc("흡인 위험.","Aspiration risk.") }, { text: loc("강한 흡인력의 젖꼭지","Strong-vacuum nipple"), effect: { hp: -25, rep: -15 }, log: loc("환아가 빨기 어려움.","Hard for infant to suck.") }, { text: loc("처음부터 NG tube","NG tube from start"), effect: { hp: -28, rep: -20 }, log: loc("필요 시만 사용.","Only when needed.") }]) }; }
function generateCerebralPalsyQuestion() { return { baseId: "cerebralPalsy", categoryKey: "pediatric", part: loc("신경 발달","Neurodevelopmental"), emoji: "👦", title: loc("뇌성 마비 핵심 간호","Cerebral Palsy Care"), desc: loc(`뇌성마비 아동의 가장 핵심적인 간호 목표는?`,`Core nursing goal for a child with cerebral palsy?`), choices: shuffle([{ text: loc("최대 기능·독립성 향상 + 영양·구축 예방","Maximize function/independence + nutrition + prevent contractures"), effect: { hp: -2, rep: 22 }, log: loc("정답. 다학제 접근.","Correct. Multidisciplinary approach.") }, { text: loc("완치 목표 약물","Curative medication"), effect: { hp: -32, rep: -22 }, log: loc("CP는 비진행성·완치 없음.","CP is non-progressive, no cure.") }, { text: loc("절대 안정","Strict bed rest"), effect: { hp: -38, rep: -28 }, log: loc("구축 가속.","Accelerates contractures.") }, { text: loc("학교 출석 금지","Forbid school attendance"), effect: { hp: -32, rep: -22 }, log: loc("사회 발달이 중요.","Social development matters.") }]) }; }
function generatePolyharmacyQuestion() { return { baseId: "polypharmacy", categoryKey: "adult", part: loc("노인 간호","Geriatrics"), emoji: "💊", title: loc("노인 다약제 (Polypharmacy)","Polypharmacy"), desc: loc(`5가지 이상 약을 복용하는 노인의 가장 큰 위험은?`,`Greatest risk in an elderly patient on 5+ medications?`), choices: shuffle([{ text: loc("약물상호작용·낙상·인지 저하","Drug interactions, falls, cognitive impairment"), effect: { hp: -2, rep: 22 }, log: loc("정답. Beers Criteria로 부적절 약 점검.","Correct. Use Beers Criteria for inappropriate meds.") }, { text: loc("효과가 더 좋음","Greater effectiveness"), effect: { hp: -32, rep: -22 }, log: loc("부작용 ↑.","Side effects ↑.") }, { text: loc("비용 절감","Cost savings"), effect: { hp: -28, rep: -20 }, log: loc("비용 ↑.","Costs ↑.") }, { text: loc("관계 없음","No effect"), effect: { hp: -38, rep: -28 }, log: loc("심각한 위험.","Significant risk.") }]) }; }
function generateMorseFallScaleQuestion() { return { baseId: "morseFall", categoryKey: "fundamentals", part: loc("낙상 위험","Fall Risk"), emoji: "🏃", title: loc("Morse 낙상 사정","Morse Fall Scale"), desc: loc(`Morse Fall Scale에서 점수가 높은 환자에게 가장 적절한 중재는?`,`Best intervention for high Morse Fall Scale score?`), choices: shuffle([{ text: loc("호출벨 가까이·낮은 침대·노란 손목띠·동행 보행","Call bell within reach, bed low, yellow band, supervised ambulation"), effect: { hp: -2, rep: 22 }, log: loc("정답. 다중 안전 중재.","Correct. Multi-modal safety bundle.") }, { text: loc("신체보호대 즉시","Immediate restraints"), effect: { hp: -32, rep: -22 }, log: loc("최후 수단·법적 절차 필요.","Last resort, requires legal process.") }, { text: loc("관찰만","Just observe"), effect: { hp: -32, rep: -22 }, log: loc("적극 예방 필요.","Active prevention needed.") }, { text: loc("절대 안정","Strict bed rest"), effect: { hp: -28, rep: -20 }, log: loc("탈조건화·욕창 위험.","Deconditioning/pressure ulcer risk.") }]) }; }
function generateStatinMyopathyQuestion() { return { baseId: "statinMyopathy", categoryKey: "adult", part: loc("스타틴","Statins"), emoji: "💊", title: loc("스타틴 부작용","Statin Side Effects"), desc: loc(`스타틴 복용 환자에서 모니터해야 할 가장 심각한 부작용은?`,`Most serious side effect to monitor in statin patient?`), choices: shuffle([{ text: loc("횡문근융해증 (CK·신부전)","Rhabdomyolysis (CK ↑, renal failure)"), effect: { hp: -3, rep: 22 }, log: loc("정답. 근육통·짙은 소변·CK >10x ULN.","Correct. Myalgia, dark urine, CK >10x ULN.") }, { text: loc("탈모","Hair loss"), effect: { hp: -22, rep: -12 }, log: loc("드물고 가역적.","Rare and reversible.") }, { text: loc("체중 증가","Weight gain"), effect: { hp: -22, rep: -12 }, log: loc("주된 부작용 아님.","Not main side effect.") }, { text: loc("불면","Insomnia"), effect: { hp: -22, rep: -12 }, log: loc("드뭄.","Rare.") }]) }; }
function generateACEInhibitorQuestion() { return { baseId: "aceInhibitor", categoryKey: "adult", part: loc("심혈관 약물","CV Drugs"), emoji: "💊", title: loc("ACE 억제제 부작용","ACE Inhibitor Side Effects"), desc: loc(`Captopril 복용 환자가 마른 기침을 호소한다. 적절한 처치는?`,`Patient on captopril complains of dry cough. Appropriate action?`), choices: shuffle([{ text: loc("ARB(Losartan 등)로 교체","Switch to an ARB (e.g., losartan)"), effect: { hp: -2, rep: 22 }, log: loc("정답. ACE-i의 흔한 부작용·ARB는 기침 적음.","Correct. Common ACE-i side effect; ARBs less coughy.") }, { text: loc("기침억제제 추가","Add cough suppressant"), effect: { hp: -25, rep: -15 }, log: loc("원인 약물 교체가 우선.","Switch the cause first.") }, { text: loc("용량 즉시 두 배","Double the dose"), effect: { hp: -32, rep: -22 }, log: loc("증상 악화.","Worsens.") }, { text: loc("관찰만","Just observe"), effect: { hp: -22, rep: -12 }, log: loc("대안이 있음.","There are alternatives.") }]) }; }
function generateITPQuestion() { return { baseId: "itp", categoryKey: "adult", part: loc("혈액","Hematology"), emoji: "🩹", title: loc("ITP","Immune Thrombocytopenia"), desc: loc(`ITP 환자(혈소판 20,000)에게 가장 중요한 환자 교육은?`,`Most important teaching for an ITP patient (platelets 20,000)?`), choices: shuffle([{ text: loc("출혈 예방 (부드러운 칫솔, 면도기 X, 외상 X, 코·잇몸 출혈 보고)","Bleeding precautions (soft brush, no razor, no contact, report nose/gum bleeds)"), effect: { hp: -3, rep: 22 }, log: loc("정답. <50k 시 출혈 위험.","Correct. <50k = bleed risk.") }, { text: loc("심한 운동 권장","Encourage vigorous exercise"), effect: { hp: -38, rep: -28 }, log: loc("출혈 위험.","Bleed risk.") }, { text: loc("아스피린 매일","Daily aspirin"), effect: { hp: -42, rep: -32 }, log: loc("절대 금기.","Absolutely contraindicated.") }, { text: loc("IM 주사 권장","Encourage IM injections"), effect: { hp: -32, rep: -22 }, log: loc("혈종 위험.","Hematoma risk.") }]) }; }
function generateAnorexiaTreatmentQuestion() { return { baseId: "anorexiaTx", categoryKey: "psych", part: loc("섭식장애","Eating Disorder"), emoji: "🍽️", title: loc("거식증 치료 우선순위","Anorexia Treatment Priority"), desc: loc(`심한 저체중 거식증 환자의 1순위 치료 목표는?`,`Top priority goal for severely underweight anorexia patient?`), choices: shuffle([{ text: loc("의학적 안정화 + 점진적 체중 회복 + 다학제 치료","Medical stabilization + gradual weight restoration + multidisciplinary care"), effect: { hp: -3, rep: 22 }, log: loc("정답. 재영양 증후군 주의.","Correct. Watch for refeeding syndrome.") }, { text: loc("강제 폭식 시키기","Force binge eating"), effect: { hp: -45, rep: -32 }, log: loc("재영양 증후군·심정지 위험.","Refeeding syndrome / cardiac arrest.") }, { text: loc("약물만으로 치료","Medication alone"), effect: { hp: -28, rep: -20 }, log: loc("심리치료가 핵심.","Therapy is core.") }, { text: loc("관찰만","Just observe"), effect: { hp: -42, rep: -32 }, log: loc("사망률 높음.","High mortality.") }]) }; }
function generatePTSDTherapyQuestion() { return { baseId: "ptsdTherapy", categoryKey: "psych", part: loc("PTSD 치료","PTSD Therapy"), emoji: "🧠", title: loc("PTSD 1차 치료","PTSD First-Line"), desc: loc(`PTSD의 1차 심리치료는?`,`First-line psychotherapy for PTSD?`), choices: shuffle([{ text: loc("외상중심 인지행동치료 또는 EMDR","Trauma-focused CBT or EMDR"), effect: { hp: -2, rep: 22 }, log: loc("정답. 약물은 SSRI/SNRI 보조.","Correct. SSRIs/SNRIs are adjuncts.") }, { text: loc("벤조다이아제핀 장기","Long-term benzos"), effect: { hp: -32, rep: -22 }, log: loc("권장하지 않음.","Not recommended.") }, { text: loc("외상 자세히 강제 회상","Force detailed trauma recall"), effect: { hp: -38, rep: -28 }, log: loc("재외상화 위험.","Risk of retraumatization.") }, { text: loc("환자 격리","Isolate patient"), effect: { hp: -32, rep: -22 }, log: loc("부적절.","Inappropriate.") }]) }; }

